 1	import React, { FC } from 'react';
 2	import { useFieldArray, useFormContext } from 'react-hook-form';
 3	
 4	import { IoK8sApiCoreV1Service } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 5	import { Button, ButtonVariant } from '@patternfly/react-core';
 6	import { PlusCircleIcon } from '@patternfly/react-icons';
 7	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 8	import { getName } from '@utils/resources/shared';
 9	import { RouteKind } from '@utils/types';
10	import { isEmpty } from '@utils/utils';
11	
12	import AlternateService from './AlternateService';
13	
14	type AlternateServicesSectionProps = {
15	  services: IoK8sApiCoreV1Service[];
16	};
17	
18	const AlternateServicesSection: FC<AlternateServicesSectionProps> = ({ services }) => {
19	  const { t } = useNetworkingTranslation();
20	
21	  const { control, watch } = useFormContext<RouteKind>();
22	
23	  const { append, fields } = useFieldArray({ control, name: 'spec.alternateBackends' });
24	
25	  const selectedServiceNames = watch('spec.alternateBackends')?.map((field) => field.name) || [];
26	  const filteredServices = (services || []).filter(
27	    (service) => !selectedServiceNames.includes(getName(service)),
28	  );
29	
30	  return (
31	    <>
32	      {fields.map((field, index) => (
33	        <AlternateService
34	          field={field}
35	          filteredServices={filteredServices}
36	          index={index}
37	          key={field.id}
38	        />
39	      ))}
40	
41	      {!isEmpty(filteredServices) && (
42	        <Button
43	          className="pf-m-link--align-left co-create-route__add-service-btn"
44	          isInline
45	          onClick={() => append({ kind: 'Service', name: '', weight: 100 })}
46	          type="button"
47	          variant={ButtonVariant.link}
48	        >
49	          <PlusCircleIcon className="co-icon-space-r" />
50	          {t('Add alternate Service')}
51	        </Button>
52	      )}
53	    </>
54	  );
55	};
56	
57	export default AlternateServicesSection;

